ucs.kql:
let SprayWindow = 1h;
let MinFailedAccounts = 15;
let SprayIPs =
    AADSignInEventsBeta
    | where Timestamp > ago(7d)
    | where ErrorCode in (50053, 50126, 50055, 50056, 50057, 50064)
    | summarize FailedUsers=dcount(AccountUpn), SampleUsers=make_set(AccountUpn, 25), FirstFail=min(Timestamp), LastFail=max(Timestamp) by IPAddress, bin(Timestamp, SprayWindow)
    | where FailedUsers >= MinFailedAccounts;
let Successes =
    AADSignInEventsBeta
    | where ErrorCode == 0
    | project SuccessTime=Timestamp, IPAddress, SuccessUser=AccountUpn, ClientAppUsed, Country;
SprayIPs
| join kind=inner Successes on IPAddress
| where SuccessTime between (FirstFail .. LastFail + 2h)
| join kind=inner (
    DeviceLogonEvents
    | where ActionType == "LogonSuccess"
    | where LogonType in ("RemoteInteractive","Network")
    | project LMTime=Timestamp, DeviceName, AccountName=tolower(AccountName), RemoteIP, LogonType
) on $left.SuccessUser == $right.AccountName
| where LMTime between (SuccessTime .. SuccessTime + 6h)
| project FirstFail, IPAddress, FailedUsers, SuccessTime, SuccessUser, Country, LMTime, DeviceName, RemoteIP, LogonType, SampleUsers
